import{_ as i,o as l,c as e,al as t}from"./chunks/framework.BOATtE-F.js";const g=JSON.parse('{"title":"开发文档","description":"","frontmatter":{"title":"开发文档","next":{"text":"附属开发","link":"/posts/docs/addon/index"}},"headers":[],"relativePath":"posts/docs/index.md","filePath":"posts/docs/index.md","lastUpdated":1773840449000}'),r={name:"posts/docs/index.md"};function n(o,a,s,d,h,c){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="开发文档" tabindex="-1">开发文档 <a class="header-anchor" href="#开发文档" aria-label="Permalink to “开发文档”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>AnvilCraft 开发文档为模组开发者和内容创作者提供了全面的技术指南，涵盖了从附属模组开发到数据包定制的各个方面。</p><h3 id="文档结构" tabindex="-1">文档结构 <a class="header-anchor" href="#文档结构" aria-label="Permalink to “文档结构”">​</a></h3><p>本文档分为四个主要部分：</p><h4 id="_1-附属开发-addon" tabindex="-1">1. <a href="./addon/">附属开发 (Addon)</a> <a class="header-anchor" href="#_1-附属开发-addon" aria-label="Permalink to “1. 附属开发 (Addon)”">​</a></h4><p>指导开发者如何创建基于 AnvilCraft 核心的附属模组，包括：</p><ul><li>环境搭建与开发工具配置</li><li>物品和方块的创建与注册</li><li>使用 Registrate 系统进行内容管理</li><li>NeoForge 模组开发最佳实践</li></ul><h4 id="_2-数据包-datapack" tabindex="-1">2. <a href="./datapack/">数据包 (Datapack)</a> <a class="header-anchor" href="#_2-数据包-datapack" aria-label="Permalink to “2. 数据包 (Datapack)”">​</a></h4><p>详细介绍 AnvilCraft 的数据包系统，现已覆盖 32 种配方类型：</p><ul><li><strong>基础工艺配方</strong>：物品/方块压缩、粉碎、解包</li><li><strong>特殊工艺配方</strong>：冲压、膨发、挤压、注入</li><li><strong>环境交互配方</strong>：InWorld 世界内配方、烹饪、超级加热</li><li><strong>高级配方</strong>：时移、多方块结构、生物转换</li><li><strong>装饰配方</strong>：珠宝制作、矿物涌泉、方块涂抹</li><li><strong>扩展机制配方</strong>：筛网、煮沸、中子辐照、质量注入、铁砧碰撞工艺</li><li><strong>专用系统配方</strong>：多方块转换、带物品生物转换、多重合一锻造、霜铸变换、充放电、能量武器制作</li></ul><p>每种配方类型都提供详细的 JSON 结构说明和使用示例。</p><h4 id="_3-kubejs-集成" tabindex="-1">3. <a href="./kubejs/">KubeJS 集成</a> <a class="header-anchor" href="#_3-kubejs-集成" aria-label="Permalink to “3. KubeJS 集成”">​</a></h4><p>提供 AnvilCraft 与 KubeJS 脚本系统的完整集成指南，支持：</p><ul><li>所有数据包配方类型的脚本化实现</li><li>KubeJS 风格的链式调用 API</li><li>丰富的构建器方法和实用工具</li><li>详细的代码示例和最佳实践</li></ul><h4 id="_4-anvillib-开发库" tabindex="-1">4. <a href="./anvillib/">AnvilLib 开发库</a> <a class="header-anchor" href="#_4-anvillib-开发库" aria-label="Permalink to “4. AnvilLib 开发库”">​</a></h4><p>AnvilLib 的完整开发文档，涵盖所有功能模块：</p><ul><li><strong>Config</strong>：基于注解的配置系统</li><li><strong>Integration</strong>：模组兼容性集成框架</li><li><strong>Network</strong>：网络包自动注册</li><li><strong>Recipe</strong>：世界内配方系统</li><li><strong>Moveable Entity Block</strong>：可被活塞推动的方块实体</li><li><strong>Registrum</strong>：链式注册 API</li></ul><hr><p>无论您是想要创建功能丰富的附属模组，还是希望通过数据包和脚本定制游戏体验，这份文档都能为您提供所需的指导和技术支持。</p>',20)])])}const _=i(r,[["render",n]]);export{g as __pageData,_ as default};
